import anthropic
from composio_anthropic import ComposioToolSet, App
from composio.exceptions import ComposioClientError

client = anthropic.Anthropic()

def safe_run_agent(user_id: str, task: str) -> dict:
    """
    Run a Composio-backed agent with structured error handling.
    Returns {ok: True, result: str} or {ok: False, error: str, action: str}.
    """
    try:
        toolset = ComposioToolSet(entity_id=user_id)
        tools = toolset.get_tools(apps=[App.GITHUB])
    except ComposioClientError as exc:
        if "not connected" in str(exc).lower():
            return {
                "ok": False,
                "error": "AUTH_REQUIRED",
                "message": "GitHub account not connected for this user",
                "action": "connect_github",
            }
        return {"ok": False, "error": "PLATFORM_ERROR", "message": str(exc)}

    messages = [{"role": "user", "content": task}]
    for _ in range(10):   # guard against infinite loops
        try:
            resp = client.messages.create(
                model="claude-sonnet-4-6", max_tokens=1024,
                tools=tools, messages=messages,
            )
        except anthropic.APIError as exc:
            return {"ok": False, "error": "API_ERROR", "message": str(exc)}

        if resp.stop_reason == "end_turn":
            text = next((b.text for b in resp.content if hasattr(b, "text")), "")
            return {"ok": True, "result": text}

        messages.append({"role": "assistant", "content": resp.content})
        try:
            tool_results = toolset.handle_tool_calls(resp)
        except ComposioClientError as exc:
            return {"ok": False, "error": "TOOL_ERROR", "message": str(exc)}
        messages.append({"role": "user", "content": tool_results})

    return {"ok": False, "error": "MAX_ITERATIONS", "message": "Agent loop exceeded 10 iterations"}
